1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	// Rounds up in MHPCO's favor, guarding against floating-point drift
25	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
26	const roundUpInFavor = (amount: number): number =>
27	  Math.ceil(Number(amount.toFixed(6)));
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE_PREMIUM = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	// A same-type group of exactly BLOCK_SIZE components forms one block priced at
37	// BLOCK_BASE_PREMIUM; any other count is priced per component. (Multi-block and
38	// block-plus-leftover pricing are not yet implemented.)
39	const componentGroupBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : count * COMPONENT_BASE_PREMIUM;
43	
44	const itemBasePremium = (item: Item): number =>
45	  isComponent(item) ? COMPONENT_BASE_PREMIUM : BASE_PREMIUMS[item.type];
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const FIRST_INSURANCE_RATE = 0.1;
49	
50	const itemSurcharge = (item: Item): number =>
51	  item.cursed ? CURSE_SURCHARGE_RATE * itemBasePremium(item) : 0;
52	
53	const countByType = (items: Item[]): Record<string, number> =>
54	  items.reduce<Record<string, number>>((counts, item) => {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	    return counts;
57	  }, {});
58	
59	const sum = (values: number[]): number =>
60	  values.reduce((running, value) => running + value, 0);
61	
62	const basePremiumTotal = (items: Item[]): number => {
63	  const mainItems = items.filter((item) => !isComponent(item));
64	  const components = items.filter(isComponent);
65	
66	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
67	  const componentsTotal = sum(
68	    Object.values(countByType(components)).map(componentGroupBasePremium),
69	  );
70	
71	  return mainItemsTotal + componentsTotal;
72	};
73	
74	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
75	  const policyBase = basePremiumTotal(items);
76	  const surcharges = sum(items.map(itemSurcharge));
77	  const policyModifiers = policyBase * FIRST_INSURANCE_RATE;
78	  const exactPremium = policyBase + surcharges + policyModifiers + PROCESSING_FEE;
79	  return { premium: roundUpInFavor(exactPremium) };
80	};
81	
82	export const claim = (...args: unknown[]): unknown => {
83	  return undefined;
84	};
